    struct dwc3_gadget *gadget = container_of(req->dev, struct dwc3_gadget, gadget);

    // Lock the list manipulation
    spin_lock(&gadget->lock);

    // Check if the request is already completed
    if (list_empty(&req->list)) {
        spin_unlock(&gadget->lock);
        return;
    }

    // Remove the request from the list
    list_del(&req->list);

    // Unmap the request
    usb_gadget_unmap_request_by_dev(req->dev, req, req->dma);

    // Unlock the list manipulation
    spin_unlock(&gadget->lock);

    // Complete the request with the given status
    usb_request_complete(req, status);
}
```

