#define MAX_LINE_LENGTH 4096

int copy_asoundrc(const char *src_path, const char *dest_path) {
    char *user_home;
    char *full_dest_path;
    struct stat st;
    int ret = -1;

    // Get the user's home directory
    if (getenv("HOME") == NULL) {
        fprintf(stderr, "Environment variable HOME not set.\n");
        return -1;
    }
    user_home = getenv("HOME");

    // Construct the full destination path
    full_dest_path = malloc(strlen(user_home) + strlen(dest_path) + 2);
    if (full_dest_path == NULL) {
        fprintf(stderr, "Memory allocation failed.\n");
        return -1;
    }
    snprintf(full_dest_path, sizeof(full_dest_path), "%s/%s", user_home, dest_path);

    // Check if the destination is a symbolic link
    if (lstat(full_dest_path, &st) == 0 && S_ISLNK(st.st_mode)) {
        fprintf(stderr, "Destination is a symbolic link.\n");
        free(full_dest_path);
        return -1;
    }

    // Fork a new process
    pid_t pid = fork();
    if (pid == -1) {
        fprintf(stderr, "Fork failed.\n");
        free(full_dest_path);
        return -1;
    } else if (pid == 0) {
        // Child process
        // Change the owner and permissions
        if (chown(full_dest_path, getuid(), getgid()) != 0) {
            perror("chown");
            exit(EXIT_FAILURE);
        }
        if (chmod(full_dest_path, 0644) != 0) {
            perror("chmod");
            exit(EXIT_FAILURE);
        }

        // Copy the file
        FILE *src = fopen(src_path, "r");
        FILE *dest = fopen(full_dest_path, "w");
        if (src == NULL || dest == NULL) {
            perror("fopen");
            exit(EXIT_FAILURE);
        }

        char line[MAX_LINE_LENGTH];
        while (fgets(line, sizeof(line), src) != NULL) {
            fputs(line, dest);
        }

        fclose(src);
        fclose(dest);

        // Exit the child process
        exit(EXIT_SUCCESS);
    } else {
        // Parent process
        // Wait for the child process to finish
        waitpid(pid, &ret, 0);
        if (WIFEXITED(ret) && WEXITSTATUS(ret) == EXIT_SUCCESS) {
            ret = 0;
        }
    }

    free(full_dest_path);
    return ret;
}
