#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <zip.h>

#define ZIP64_EXT_LEN 12

// Function to read a buffer from a file
int readbuf(FILE *file, void *buffer, size_t size) {
    return fread(buffer, 1, size, file);
}

// Function to extract a file from a ZIP archive
int extract_or_test_entrylist(zip_t *zip, const char *filename, const char *output_path, int test_only) {
    zip_stat_t stat;
    zip_entry_t *entry;
    FILE *output_file;
    void *buffer;
    size_t size, read_size;
    int result = 0;

    // Check if the file exists
    if (zip_stat(zip, filename, 0, &stat) != ZIP_OK) {
        fprintf(stderr, "File %s does not exist in the ZIP archive.\n", filename);
        return -1;
    }

    // Check if the file should be overwritten
    if (!test_only) {
        output_file = fopen(output_path, "r");
        if (output_file) {
            fprintf(stderr, "File %s already exists. Overwrite? (y/n): ", output_path);
            char choice;
            scanf(" %c", &choice);
            fclose(output_file);
            if (choice != 'y' && choice != 'Y') {
                fprintf(stderr, "File extraction cancelled.\n");
                return -1;
            }
        }
    }

    // Open the output file for writing
    output_file = fopen(output_path, "wb");
    if (!output_file) {
        fprintf(stderr, "Failed to open output file %s.\n", output_path);
        return -1;
    }

    // Create a buffer to read data from the ZIP archive
    buffer = malloc(stat.size);
    if (!buffer) {
        fprintf(stderr, "Failed to allocate memory for buffer.\n");
        fclose(output_file);
        return -1;
    }

    // Open the ZIP entry
    entry = zip_entry_open(zip, filename);
    if (!entry) {
        fprintf(stderr, "Failed to open ZIP entry %s.\n", filename);
        free(buffer);
        fclose(output_file);
        return -1;
    }

    // Read the data from the ZIP entry
    while ((read_size = readbuf(zip, buffer, stat.size)) > 0) {
        fwrite(buffer, 1, read_size, output_file);
    }

    // Close the ZIP entry and the output file
    zip_entry_close(entry);
    fclose(output_file);

    // Free the buffer
    free(buffer);

    // Check if the file was extracted successfully
    if (test_only) {
        result = 0; // No extraction for testing
    } else {
        result = 1; // Extraction successful
    }

    return result;
}

// Function to check if a ZIP file is valid
int is_valid_zip(const char *filename) {
    FILE *file;
    int result = 0;

    file = fopen(filename, "rb");
    if (file) {
        char signature[4];
        readbuf(file, signature, 4);
        if (memcmp(signature, "PK\x03\x04", 4) == 0) {
            result = 1; // Valid ZIP file
        }
        fclose(file);
    }

    return result;
}

// Main function to demonstrate the usage of extract_or_test_entrylist
int main() {
    const char *zip_filename = "example.zip";
    const char *output_filename = "extracted_file.txt";

    if (!is_valid_zip(zip_filename)) {
        fprintf(stderr, "The file %s is not a valid ZIP file.\n", zip_filename);
        return -1;
    }

    zip_t *zip = zip_open(zip_filename, ZIP_RDONLY, NULL);
    if (!zip) {
        fprintf(stderr, "Failed to open the ZIP file %s.\n", zip_filename);
        return -1;
    }

    int result = extract_or_test_entrylist(zip, "file_in_zip.txt", output_filename, 0); // 0 for extraction, 1 for testing
    if (result == 1) {
        printf("File extracted successfully.\n");
    } else if (result == 0) {
        printf("File extraction cancelled.\n");
    } else {
        printf("Failed to extract file.\n");
    }

    zip_close(zip);

    return 0;
}
