// Function to open a secure IMAP connection using STARTTLS
IMAPConnection *imap_open_connection(const char *hostname, int port) {
    IMAPConnection *imap = (IMAPConnection *)malloc(sizeof(IMAPConnection));
    if (imap == NULL) {
        return NULL;
    }

    // Initialize SSL library
    SSL_library_init();
    SSL_load_error_strings();
    OpenSSL_add_all_algorithms();

    // Create a socket
    imap->fd = mutt_socket_open(hostname, port, SOCK_STREAM);
    if (imap->fd == INVALID_SOCKET) {
        free(imap);
        return NULL;
    }

    // Create an SSL context
    SSL_CTX *ctx = SSL_CTX_new(TLS_client_method());
    if (ctx == NULL) {
        free(imap);
        return NULL;
    }

    // Create an SSL object
    imap->ssl = SSL_new(ctx);
    if (imap->ssl == NULL) {
        SSL_CTX_free(ctx);
        free(imap);
        return NULL;
    }

    // Set the socket for SSL
    SSL_set_fd(imap->ssl, imap->fd);

    // Attempt to start TLS
    if (mutt_ssl_starttls(imap->ssl) != 0) {
        SSL_free(imap->ssl);
        SSL_CTX_free(ctx);
        mutt_socket_close(imap->fd);
        free(imap);
        return NULL;
    }

    // Set the hostname and port
    imap->hostname = strdup(hostname);
    imap->port = port;
    imap->tls_enabled = true;

    return imap;
}

