// Function to add or modify a principal in the LDAP directory
int add_modify_principal(LDAP *ldap, const char *dn, const char *realm, const char *subtree, const char *principal, const char *password, const char *new_password) {
    int rc = LDAP_SUCCESS;
    LDAPMessage *res = NULL;
    LDAPMod *mods[5];
    char *new_principal = NULL;

