    if (strcmp(realm, "example.com") != 0) {
        fprintf(stderr, "Realm validation failed\n");
        return LDAP_INVALID_ATTRIBUTE_SYNTAX;
    }
    if (strcmp(subtree, "ou=users,dc=example,dc=com") != 0) {
        fprintf(stderr, "Subtree validation failed\n");
        return LDAP_INVALID_ATTRIBUTE_SYNTAX;
    }

