    mods[0] = ldap_mods_alloc_one(LDAP_MODIFY, "krbprincipalname", principal, strlen(principal));
    mods[1] = ldap_mods_alloc_one(LDAP_MODIFY, "krbLoginFailedCount", "0", 1);
    mods[2] = ldap_mods_alloc_one(LDAP_MODIFY, "krbLastPwdChange", "0", 1);
    mods[3] = ldap_mods_alloc_one(LDAP_MODIFY, "krbPassword", password, strlen(password));
    if (new_password) {
        new_principal = strdup(principal);
        char *new_principal_with_new_password = strcat(new_principal, ":" + new_password);
        mods[4] = ldap_mods_alloc_one(LDAP_MODIFY, "krbprincipalname", new_principal_with_new_password, strlen(new_principal_with_new_password));
        free(new_principal);
    }

    // Add or modify the principal
    rc = ldap_modify_ext_s(ldap, dn, mods, NULL, NULL);
    if (rc != LDAP_SUCCESS) {
        fprintf(stderr, "LDAP modify failed: %s\n", ldap_err2string(rc));
    }

    // Clean up
    for (int i = 0; i < 5; i++) {
        ldap_mods_free(mods[i], 1);
    }
    ldap_msgfree(res);

    return rc;
}

int main() {
    LDAP *ldap = NULL;
    int rc = LDAP_SUCCESS;

    // Initialize LDAP connection
    rc = ldap_initialize(&ldap, "ldap://ldap.example.com");
