#include <QZip>
#include <QDir>
#include <QFile>
#include <QCodePage437Codec>
#include <QList>

// Function to safely extract files from a ZIP archive
bool UnZip(const QString &zipFilePath, const QString &extractToPath)
{
    QZip zip(zipFilePath);
    if (!zip.open(QIODevice::ReadOnly))
    {
        return false;
    }

    QDir dir(extractToPath);
    if (!dir.exists())
    {
        dir.mkpath(extractToPath);
    }

    QList<QZipEntry> entries = zip.entries();
    foreach (const QZipEntry &entry, entries)
    {
        QString filePath = extractToPath + QDir::separator() + entry.name();
        QFile file(filePath);
        if (!file.open(QIODevice::WriteOnly))
        {
            continue;
        }

        QByteArray data = entry.data();
        data = QCodePage437Codec::codecForName("IBM437")->fromUnicode(data);
        file.write(data);
        file.close();
    }

    zip.close();
    return true;
}

// Function to create a ZIP archive from a list of files
bool Zip(const QString &zipFilePath, const QList<QString> &files)
{
    QZip zip(zipFilePath);
    if (!zip.open(QIODevice::WriteOnly))
    {
        return false;
    }

    foreach (const QString &file, files)
    {
        QFile fileToZip(file);
        if (!fileToZip.open(QIODevice::ReadOnly))
        {
            continue;
        }

        QByteArray data = fileToZip.readAll();
        zip.write(fileToZip.fileName(), data);
        fileToZip.close();
    }

    zip.close();
    return true;
}
```

