int SVGElementNameCompare(SVGElement *element1, SVGElement *element2) {
    return strcmp(element1->name, element2->name);
}

// Function to format SVG element attributes to a file
void FormatSVGAttributes(FILE *output, SVGElement *element) {
    for (int i = 0; i < element->num_attributes; i++) {
        fprintf(output, " %s=\"%s\"", element->attributes[i].name, element->attributes[i].value);
    }
}

// Function to format SVG element to a file
void FormatSVGElement(FILE *output, SVGElement *element) {
    fprintf(output, "<%s", element->name);
    FormatSVGAttributes(output, element);
    fprintf(output, ">\n");
}

// Function to handle SVG element closure
void SVGEndElement(SVGDocument *document, SVGElement *element) {
    // Handle namespace management
    if (document->namespace_level > 0) {
        fprintf(document->output, "</%s>\n", element->name);
    }

    // Handle graphic context management
    if (document->current == element) {
        document->current = document->current->parent;
    }

    // Handle document state management
    if (document->root == element) {
        document->root = document->root->parent;
    }

    // Handle errors gracefully
    if (document->output == NULL) {
        fprintf(stderr, "Error: Output file is not open.\n");
        exit(EXIT_FAILURE);
