// Define a custom random number generator using PhiloxRandom
class PhiloxRandom {
public:
    PhiloxRandom() {
        // Initialize PhiloxRandom with a seed
        state[0] = 1234567890;
        state[1] = 9876543210;
    }

    double operator()() {
        // Philox random number generator implementation
        uint64_t x0 = state[0];
        uint64_t x1 = state[1];
        uint64_t z = x0 + x1;
        uint64_t y = z * 2685821657736338717;
        state[0] = x1;
        state[1] = (z >> 12) ^ y;
        return static_cast<double>(y) / std::numeric_limits<uint64_t>::max();
    }

private:
    uint64_t state[2];
};

// Function to perform vectorized uniform rejection sampling
template <typename T>
Eigen::Tensor<T, 2> uniform_rejection_sampling(const Eigen::Tensor<T, 1>& lower_bound, const Eigen::Tensor<T, 1>& upper_bound, int batch_size, int sample_shape) {
    Eigen::Tensor<T, 2> samples(batch_size, sample_shape);
    PhiloxRandom rng;

    for (int i = 0; i < batch_size; ++i) {
        for (int j = 0; j < sample_shape; ++j) {
            double u = rng();
            while (u >= (upper_bound(i, j) - lower_bound(i, j)) / (upper_bound(i, j) - lower_bound(i, j))) {
                u = rng();
            }
            samples(i, j) = lower_bound(i, j) + u * (upper_bound(i, j) - lower_bound(i, j));
        }
    }

    return samples;
}

// Example usage
int main() {
    Eigen::Tensor<double, 1> lower_bound(3, 3);
    lower_bound << 0.0, 0.0, 0.0,
                  1.0, 1.0, 1.0,
                  2.0, 2.0, 2.0;

    Eigen::Tensor<double, 1> upper_bound(3, 3);
    upper_bound << 1.0, 1.0, 1.0,
                  2.0, 2.0, 2.0,
                  3.0, 3.0, 3.0;

    int batch_size = 10;
    int sample_shape = 3;

    Eigen::Tensor<double, 2> samples = uniform_rejection_sampling(lower_bound, upper_bound, batch_size, sample_shape);
    // Output the samples
    std::cout << "Samples:\n" << samples << std::endl;
    return 0;
}
