#include <llhttp.h>
#include <stdio.h>
#include <stdlib.h>

// Define a structure to hold the parsed message
typedef struct {
    char *method;
    char *path;
    char *version;
    char *body;
    int status_code;
    int content_length;
} ParsedMessage;

// Callback function for header processing
static int header_cb(llhttp_t *h, const char *name, size_t namelen, const char *value, size_t valuelen) {
    if (llhttp_method(h) == LLHTTP_METHOD_GET || llhttp_method(h) == LLHTTP_METHOD_HEAD) {
        if (strcmp(name, "Content-Length") == 0) {
            h->content_length = atoi(value);
        }
    }
    return 0;
}

// Callback function for message completion
static int message_complete_cb(llhttp_t *h) {
    ParsedMessage *msg = (ParsedMessage *)h->data;
    msg->status_code = llhttp_status_code(h);
    msg->body = (char *)malloc(h->content_length + 1);
    if (msg->body != NULL) {
        memcpy(msg->body, h->bufptr, h->content_length);
        msg->body[h->content_length] = '\0';
    }
    return 0;
}

// Function to parse an HTTP message
ParsedMessage *parse_http_message(const char *message) {
    llhttp_t h;
    ParsedMessage *msg = (ParsedMessage *)malloc(sizeof(ParsedMessage));
    if (msg == NULL) {
        return NULL;
    }
    msg->method = NULL;
    msg->path = NULL;
    msg->version = NULL;
    msg->body = NULL;
    msg->status_code = 0;
    msg->content_length = 0;

    llhttp_init(&h, LLHTTP_MODE_REQUEST);
    h.data = msg;
    h.header_cb = header_cb;
    h.message_complete_cb = message_complete_cb;

    if (llhttp_execute(&h, message, strlen(message)) != 0) {
        free(msg->method);
        free(msg->path);
        free(msg->version);
        free(msg->body);
        free(msg);
        return NULL;
    }

    return msg;
}

// Function to free the parsed message
void free_parsed_message(ParsedMessage *msg) {
    free(msg->method);
    free(msg->path);
    free(msg->version);
    free(msg->body);
    free(msg);
}

int main() {
    const char *http_message = "GET /index.html HTTP/1.1\r\nHost: example.com\r\nContent-Length: 10\r\n\r\nHello, World!";
    ParsedMessage *parsed_message = parse_http_message(http_message);

    if (parsed_message != NULL) {
        printf("Method: %s\n", parsed_message->method);
        printf("Path: %s\n", parsed_message->path);
        printf("Version: %s\n", parsed_message->version);
        printf("Status Code: %d\n", parsed_message->status_code);
        printf("Content Length: %d\n", parsed_message->content_length);
        printf("Body: %s\n", parsed_message->body);
        free_parsed_message(parsed_message);
    } else {
        printf("Failed to parse HTTP message\n");
    }

    return 0;
}
