namespace ops {
namespace micro {
namespace pooling {

TfLiteStatus AveragePool(TfLiteContext* context, TfLiteNode* node) {
  const auto* params = static_cast<TfLitePoolParams*>(node->builtin_data);
  const TfLiteTensor* input = GetInput(context, node, 0);
  TfLiteTensor* output = GetOutput(context, node, 0);

  if (input->type != kTfLiteFloat32) {
    return kTfLiteError;
  }

  if (output->type != kTfLiteFloat32) {
    return kTfLiteError;
  }

  if (input->dims->size != 4 || output->dims->size != 4) {
    return kTfLiteError;
  }

  const int32_t input_height = input->dims->data[1];
  const int32_t input_width = input->dims->data[2];
  const int32_t input_channels = input->dims->data[3];

  const int32_t output_height = params->height;
  const int32_t output_width = params->width;
  const int32_t output_channels = input_channels;

  const int32_t stride_height = params->stride_height;
  const int32_t stride_width = params->stride_width;
  const int32_t pad_height = params->padding.height;
  const int32_t pad_width = params->padding.width;

  const float output_activation_min = params->output_activation_min;
  const float output_activation_max = params->output_activation_max;

  std::vector<float> output_data(output_height * output_width * output_channels, 0.0f);

  for (int32_t h = 0; h < output_height; ++h) {
    for (int32_t w = 0; w < output_width; ++w) {
      for (int32_t c = 0; c < output_channels; ++c) {
        float sum = 0.0f;
        int count = 0;

        const int32_t input_h_start = std::max(0, h * stride_height - pad_height);
        const int32_t input_h_end = std::min(input_height, (h + 1) * stride_height + pad_height);
        const int32_t input_w_start = std::max(0, w * stride_width - pad_width);
        const int32_t input_w_end = std::min(input_width, (w + 1) * stride_width + pad_width);

        for (int32_t ih = input_h_start; ih < input_h_end; ++ih) {
          for (int32_t iw = input_w_start; iw < input_w_end; ++iw) {
            sum += input->data.f[ih * input->dims->data[1] * input->dims->data[2] + iw * input->dims->data[2] + c];
            ++count;
          }
        }

        if (count > 0) {
          output_data[h * output_width * output_channels + w * output_channels + c] =
              std::clamp(sum / count, output_activation_min, output_activation_max);
        }
      }
    }
  }

  // Copy the output data to the output tensor
  for (int32_t i = 0; i < output_data.size(); ++i) {
    output->data.f[i] = output_data[i];
  }

  return kTfLiteOk;
}

}  // namespace pooling
}  // namespace micro
}  // namespace ops
}  // namespace tflite
