// Define a structure to hold the state of the enumeration
typedef struct {
    GSocketAddressEnumerator *enumerator;
    GList *resolved_addresses;
} SocketAddressEnumeratorState;

// Callback function for g_socket_address_enumerator_next_async
static void on_address_enumerated(GObject *source_object, GAsyncResult *res, gpointer user_data) {
    SocketAddressEnumeratorState *state = (SocketAddressEnumeratorState *)user_data;
    GError *error = NULL;
    GSocketAddress *address;

    if (!g_socket_address_enumerator_next_async_finish(state->enumerator, res, &address, &error)) {
        g_warning("Failed to enumerate socket addresses: %s", error->message);
        g_clear_error(&error);
        g_list_free(state->resolved_addresses);
        g_clear_object(&state->enumerator);
        g_free(state);
        return;
    }

    if (address != NULL) {
        state->resolved_addresses = g_list_prepend(state->resolved_addresses, address);
        g_socket_address_unref(address);
    }

    // Continue enumeration
    g_socket_address_enumerator_next_async(state->enumerator, NULL, on_address_enumerated, state);
}

// Function to asynchronously resolve socket addresses
GList *async_resolve_socket_addresses(GSocketAddress *address, GError **error) {
    GSocketAddressEnumerator *enumerator;
    GList *resolved_addresses = NULL;
    SocketAddressEnumeratorState *state;

    enumerator = g_socket_address_enumerate(address, error);
    if (enumerator == NULL) {
        return NULL;
    }

    state = g_new0(SocketAddressEnumeratorState, 1);
    state->enumerator = enumerator;
    state->resolved_addresses = resolved_addresses;

    g_socket_address_enumerator_next_async(enumerator, NULL, on_address_enumerated, state);

    return resolved_addresses;
}

// Example usage
