    GSocketAddress *address = g_inet_socket_address_new_from_string("example.com", 80);
    GError *error = NULL;
    GList *resolved_addresses;

    resolved_addresses = async_resolve_socket_addresses(address, &error);
    if (resolved_addresses != NULL) {
        for (GList *l = resolved_addresses; l != NULL; l = l->next) {
            GSocketAddress *addr = l->data;
            g_print("Resolved address: %s\n", g_socket_address_to_string(addr));
            g_socket_address_unref(addr);
        }
        g_list_free(resolved_addresses);
    } else {
        g_print("Failed to resolve addresses: %s\n", error->message);
        g_clear_error(&error);
    }

    g_object_unref(address);

