int nsexec(const char *ns_path, const char *cmd) {
    int fd[2];
    pid_t child;
    struct sockaddr_un addr;

    // Create a socket pair
    if (socketpair(AF_UNIX, SOCK_STREAM, 0, fd) == -1) {
        handle_error("socketpair");
    }

    // Fork a child process
    child = fork();
    if (child == -1) {
        handle_error("fork");
    }

    if (child == 0) {
        // Child process
        close(fd[0]); // Close the read end of the socket pair

        // Unshare the mount namespace
        if (unshare(CLONE_NEWNS) == -1) {
            handle_error("unshare");
        }

        // Set the mount namespace to the specified path
        if (mount("", "/", "", MS_BIND | MS_REC, NULL) == -1) {
            handle_error("mount");
        }
        if (mount(ns_path, "/", NULL, MS_BIND | MS_REC, NULL) == -1) {
            handle_error("mount");
        }

        // Set the process as non-dumpable
        if (prctl(PR_SET_DUMPABLE, 0) == -1) {
            handle_error("prctl");
        }

        // Execute the command in the new namespace
        execlp(cmd, cmd, NULL);
        handle_error("execlp");
    } else {
        // Parent process
        close(fd[1]); // Close the write end of the socket pair

        // Wait for the child process to finish
        if (waitpid(child, NULL, 0) == -1) {
            handle_error("waitpid");
        }

        // Close the socket pair
        close(fd[0]);
    }

    return 0;
}
