static void
ews_auto_discover_cb(SoupSession *session, SoupMessage *msg, gpointer user_data) {
    EwsAutoDiscoverData *data = user_data;
    GError *error = NULL;

    if (msg->status_code == 200) {
        xmlTextWriterPtr writer = xmlNewTextWriter(data->output_buffer);
        if (writer) {
            xmlTextWriterStartDocument(writer, NULL, "UTF-8", NULL);
            xmlTextWriterStartElement(writer, BAD_CAST "Autodiscover");
            xmlTextWriterStartElement(writer, BAD_CAST "Response");
            xmlTextWriterStartElement(writer, BAD_CAST "User");
            xmlTextWriterStartElement(writer, BAD_CAST "Mailbox");
            xmlTextWriterStartElement(writer, BAD_CAST "EwsUrl");
            xmlTextWriterWriteString(writer, BAD_CAST data->uri->host);
            xmlTextWriterEndElement(writer);
            xmlTextWriterEndElement(writer);
            xmlTextWriterEndElement(writer);
            xmlTextWriterEndElement(writer);
            xmlTextWriterEndElement(writer);
            xmlTextWriterEndDocument(writer);
            xmlFreeTextWriter(writer);
        }
    } else {
        g_set_error(&error, G_IO_ERROR, G_IO_ERROR_FAILED, "Failed to discover EWS URLs: %s", msg->reason_phrase);
    }

    g_simple_async_result_set_error(data->result, error ? error->domain : G_IO_ERROR, error ? error->code : G_IO_ERROR_FAILED, error ? error->message : "Failed to discover EWS URLs");
    g_simple_async_result_complete(data->result);
    g_object_unref(data->uri);
    g_object_unref(data->output_buffer);
    g_object_unref(data->result);
    g_free(data);
}

static void
ews_auto_discover_async(GSimpleAsyncResult *result, gpointer user_data) {
    EwsAutoDiscoverData *data = user_data;
    SoupSession *session = soup_session_new();
    SoupURI *uri = soup_uri_new_with_scheme("https", data->uri->host, data->uri->port, NULL);
    xmlOutputBuffer *output_buffer = xmlOutputBufferCreateMem(NULL, 0, XML_CHAR_ENCODING_NONE);

    data->result = result;
    data->uri = soup_uri_new_with_scheme("https", data->uri->host, data->uri->port, NULL);
    data->output_buffer = output_buffer;

    soup_session_queue_message(session, soup_message_new("GET", uri), ews_auto_discover_cb, data);
    g_object_unref(session);
    g_object_unref(uri);
}

void
e_ews_autodiscover_ws_url(GSimpleAsyncResult *result, const gchar *ews_host, gint ews_port, const gchar *ews_url, GError **error) {
    SoupURI *uri;
    EwsAutoDiscoverData *data;

    uri = soup_uri_new_with_scheme("https", ews_url, -1, NULL);
    if (!uri) {
        g_set_error(error, G_IO_ERROR, G_IO_ERROR_FAILED, "Invalid EWS URL: %s", ews_url);
        return;
    }

    data = g_new0(EwsAutoDiscoverData, 1);
    data->uri = uri;
    data->ews_host = ews_host;
    data->ews_port = ews_port;

    ews_auto_discover_async(result, data);
}
