        ap_log_rerror(APLOG_MARK, APLOG_ERR, 0, r, "OIDC: No provider configured for URI: %s", r->uri);
        return HTTP_INTERNAL_SERVER_ERROR;
    }

    const char *logout_url = provider->logout_url;
    if (!logout_url) {
        ap_log_rerror(APLOG_MARK, APLOG_ERR, 0, r, "OIDC: Logout URL not configured for provider: %s", provider->name);
        return HTTP_INTERNAL_SERVER_ERROR;
    }

    apr_uri_t uri;
    if (apr_uri_parse(r->pool, logout_url, &uri) != APR_SUCCESS) {
        ap_log_rerror(APLOG_MARK, APLOG_ERR, 0, r, "OIDC: Failed to parse logout URL: %s", logout_url);
        return HTTP_INTERNAL_SERVER_ERROR;
    }

    if (uri.host != NULL && strcmp(uri.host, r->hostname) != 0) {
        ap_log_rerror(APLOG_MARK, APLOG_ERR, 0, r, "OIDC: Logout URL host does not match current hostname: %s", uri.host);
        return HTTP_FORBIDDEN;
    }

    // Prevent HTTP header splitting
    if (apr_table_get(r->headers_in, "Referer") != NULL) {
        ap_log_rerror(APLOG_MARK, APLOG_ERR, 0, r, "OIDC: Referer header detected, potential HTTP header splitting");
        return HTTP_FORBIDDEN;
    }

    // Redirect to the logout URL
    ap_set_content_type(r, "text/html");
    ap_rprintf(r, "<html><body><h1>Logging out...</h1>");
    ap_rprintf(r, "<script type='text/javascript'>");
    ap_rprintf(r, "window.location.href = '%s';", logout_url);
    ap_rprintf(r, "</script></body></html>");

    return HTTP_MOVED_TEMPORARILY;
}
