#include <openssl/ssl.h>
#include <openssl/x509.h>

int ssl3_get_server_hello(SSL *s) {
    int ret = 0;
    X509 *peer_cert = NULL;

    // Parse ServerHello message
    // ... (existing code)

    // Check if server's certificate is present
    if (s->session->peer != NULL) {
        peer_cert = s->session->peer;
    } else {
        // Handle error if no certificate is present
        SSLerr(s, SSL_R_NO_CERTIFICATE);
        return -1;
    }

    // Validate server's certificate
    if (X509_check_chain(s->cert, s->cert->chain, s->cert->num_certs, s->ctx->cert_store, s->cert->chain, s->cert->num_certs, NULL, NULL, NULL, NULL) != 1) {
        // Handle error if certificate validation fails
        SSLerr(s, SSL_R_CERTIFICATE_VERIFY_FAILED);
        return -1;
    }

    // Additional checks for certificate validity
    if (X509_check_time(X509_get_notBefore(peer_cert), NULL) != 1 || X509_check_time(X509_get_notAfter(peer_cert), NULL) != 1) {
        // Handle error if certificate expiration is invalid
        SSLerr(s, SSL_R_CERTIFICATE_EXPIRED);
        return -1;
    }

    // If all checks pass, proceed with the handshake
    ret = ssl3_get_server_certificate(s);

    return ret;
}
