// Function to spawn a process in a Flatpak environment
gboolean spawn_process(GDBusConnection *conn, const gchar *arg_cwd_path, const gchar **arg_argv, const gchar *arg_flags, GUnixFDList *arg_fds) {
    // Validate cwd_path
    if (!g_file_test(arg_cwd_path, G_FILE_TEST_IS_DIR)) {
        g_dbus_error_set_remote_error(G_DBUS_ERROR, G_DBUS_ERROR_INVALID_ARGS, "Invalid cwd path");
        return FALSE;
    }

    // Validate arg_argv
    for (guint i = 0; arg_argv[i]; i++) {
        if (!g_file_test(arg_argv[i], G_FILE_TEST_IS_EXECUTABLE)) {
            g_dbus_error_set_remote_error(G_DBUS_ERROR, G_DBUS_ERROR_INVALID_ARGS, "Invalid argument in arg_argv");
            return FALSE;
        }
    }

    // Validate arg_flags
    if (g_strcmp0(arg_flags, "allow-root") != 0) {
        g_dbus_error_set_remote_error(G_DBUS_ERROR, G_DBUS_ERROR_INVALID_ARGS, "Invalid arg_flags");
        return FALSE;
    }

    // Prepare command
    gchar *command = g_strjoinv(" ", (gchar **)arg_argv);

    // Prepare environment
    gchar **envp = g_get_environ();

    // Spawn process
    pid_t pid = fork();
    if (pid == 0) {
        // Child process
        if (arg_fds) {
            int fd_count = g_unix_fd_list_get_length(arg_fds);
            for (int i = 0; i < fd_count; i++) {
                int fd = g_unix_fd_list_get(arg_fds, i);
                dup2(fd, i + 3);
                close(fd);
            }
        }

        // Set cwd
        if (chdir(arg_cwd_path) != 0) {
            g_critical("Failed to change directory to %s: %s", arg_cwd_path, g_strerror(errno));
            exit(EXIT_FAILURE);
        }

        // Execute command
        execve(command, (char *const *)arg_argv, envp);
        g_critical("Failed to execute command: %s", g_strerror(errno));
        exit(EXIT_FAILURE);
    } else if (pid > 0) {
        // Parent process
        g_object_unref(command);
        g_object_unref(envp);
        return TRUE;
    } else {
        // Fork failed
        g_critical("Failed to fork process: %s", g_strerror(errno));
        return FALSE;
    }
}
```

