void release_and_join_mplx(h2_mplx *mplx) {
    apr_thread_mutex_t *mutex;
    apr_status_t status;

    // Get the mutex associated with the multiplexer
    status = h2_mplx_get_mutex(mplx, &mutex);
    if (status != APR_SUCCESS) {
        ap_log_cerror(APLOG_MARK, APLOG_ERR, status, NULL,
                      "Failed to get mutex for h2_mplx_release_and_join");
        return;
    }

