int _ppdCreateFromIPP(cups_file_t *ppd_file, ipp_t *ipp, const char *printer_name) {
    int result = IPP_STATUS_OK;
    ipp_attribute_t *attrib;

    // Check for required IPP attributes
    if ((attrib = ippFindAttribute(ipp, "printer-make-and-model", IPP_TAG_STRING)) == NULL) {
        result = IPP_STATUS_ERROR_BAD_REQUEST;
        cupsFilePrintf(ppd_file, "Error: Missing 'printer-make-and-model' attribute.\n");
    } else if ((attrib = ippFindAttribute(ipp, "printer-location", IPP_TAG_STRING)) == NULL) {
        result = IPP_STATUS_ERROR_BAD_REQUEST;
        cupsFilePrintf(ppd_file, "Error: Missing 'printer-location' attribute.\n");
    }

    // Write the PPD header
    cupsFilePuts(ppd_file, "%%!PS-Adobe-3.0\n");
    cupsFilePuts(ppd_file, "%%Title: %s\n", printer_name);
    cupsFilePuts(ppd_file, "%%Creator: IPP\n");

    // Write the PPD model and location
    cupsFilePrintf(ppd_file, "%%Model: %s\n", ippGetString(attrib, 0, NULL));
    cupsFilePrintf(ppd_file, "%%Location: %s\n", ippGetString(attrib, 0, NULL));

    // Write the PPD end
    cupsFilePuts(ppd_file, "%%EOF\n");

    return result;
}
