    }
};

// Define a simple config class for demonstration purposes
class Config {
public:
    std::string getCommandPath() const {
        return "command_path";
    }
};

// Define a simple utils class for demonstration purposes
class Utils {
public:
    static void run_interactively(const std::string& command) {
        // Simulate interactive execution
        std::cout << "Running command interactively: " << command << std::endl;
    }

    static void run_program(const std::string& command) {
        // Simulate non-interactive execution
        std::cout << "Running command non-interactively: " << command << std::endl;
    }

    static std::string replace_all(const std::string& input, const std::string& old, const std::string& new) {
        std::string result = input;
        size_t pos = result.find(old);
        while (pos != std::string::npos) {
            result.replace(pos, old.length(), new);
            pos = result.find(old, pos + new.length());
        }
        return result;
    }
};

// Define the controller class
class Controller {
public:
    Controller(const Config& config, Logger& logger) : config_(config), logger_(logger) {}

    void bookmark(const std::string& url) {
        try {
            // Sanitize URL input
            std::string sanitized_url = Utils::replace_all(url, " ", "%20");

            // Construct the command using strprintf::fmt
            std::string command = "command_path " + sanitized_url;

            // Execute the command based on interactive mode
            if (config_.getCommandPath().find("interactive") != std::string::npos) {
                Utils::run_interactively(command);
            } else {
                Utils::run_program(command);
            }
        } catch (const CommandExecutionException& e) {
            logger_.log("Error executing command: " + e.what());
        } catch (const std::exception& e) {
            logger_.log("General error: " + e.what());
        }
    }

private:
    Config config_;
    Logger& logger_;
};

// Test the bookmark function
void test_bookmark() {
    Config config;
    Logger logger;
    Controller controller(config, logger);

    // Test with interactive mode
    controller.bookmark("https://example.com");
    assert(controller.config_.getCommandPath().find("interactive") != std::string::npos);

    // Test with non-interactive mode
    controller.config_.getCommandPath().replace("interactive", "non-interactive");
    controller.bookmark("https://example.com");
    assert(controller.config_.getCommandPath().find("non-interactive") != std::string::npos);

    // Test with invalid URL
    try {
        controller.bookmark("https://example.com with spaces");
        assert(false); // Should not reach here
    } catch (const CommandExecutionException& e) {
        assert(e.what() == "Error executing command: Invalid URL");
    }

    std::cout << "All tests passed!" << std::endl;
}

int main() {
    test_bookmark();
    return 0;
}
