#include <Eigen/Sparse>
#include <Eigen/Device>

// Function to perform spatial max pooling using Eigen
template <typename Device>
void SpatialMaxPool(const Device& device, Eigen::Tensor<float, 4, Device>& input, Eigen::Tensor<float, 4, Device>& output, int kernel_size, int stride) {
    int batch_size = input.dimension(0);
    int channels = input.dimension(1);
    int height = input.dimension(2);
    int width = input.dimension(3);

    int pooled_height = (height - kernel_size) / stride + 1;
    int pooled_width = (width - kernel_size) / stride + 1;

    output.resize(batch_size, channels, pooled_height, pooled_width);

    for (int b = 0; b < batch_size; ++b) {
        for (int c = 0; c < channels; ++c) {
            for (int ph = 0; ph < pooled_height; ++ph) {
                for (int pw = 0; pw < pooled_width; ++pw) {
                    int start_h = ph * stride;
                    int start_w = pw * stride;

                    float max_value = -std::numeric_limits<float>::max();
                    for (int kh = 0; kh < kernel_size; ++kh) {
                        for (int kw = 0; kw < kernel_size; ++kw) {
                            int h = start_h + kh;
                            int w = start_w + kw;

                            if (h < height && w < width) {
                                max_value = std::max(max_value, input(b, c, h, w));
                            }
                        }
                    }

                    output(b, c, ph, pw) = max_value;
                }
            }
        }
    }
}
