  v8::HandleScope handle_scope(isolate);
  v8::StackGuard::EnsureStackGuarded();

  // Create a V8 context
  v8::Local<v8::Context> context = isolate->GetCurrentContext();

  // Create a V8 function
  v8::Local<v8::Function> function = v8::Local<v8::Function>::New(isolate, GetFunction(method));

  // Create a V8 array
  v8::Local<v8::Array> array = v8::Array::New(isolate, args.size());
  for (size_t i = 0; i < args.size(); ++i) {
    array->Set(context, i, v8::Local<v8::Value>::New(isolate, args[i].Clone()));
  }

  // Create a V8 object to hold the receiver
  v8::Local<v8::Object> receiver_object = v8::Object::New(isolate);
  receiver_object->Set(context, "receiver", v8::Local<v8::Value>::New(isolate, receiver.Pass()));

  // Create a V8 object to hold the serialized arguments
  v8::Local<v8::Object> args_object = v8::Object::New(isolate);
  args_object->Set(context, "args", v8::Local<v8::Value>::New(isolate, v8::String::NewFromUtf8(isolate, serialized_args.c_str()).ToLocalChecked()));

  // Create a V8 object to hold the frame ID
  v8::Local<v8::Object> frame_id_object = v8::Object::New(isolate);
  frame_id_object->Set(context, "frameId", v8::Local<v8::Value>::New(isolate, v8::Integer::New(isolate, frame_id)));

  // Create a V8 object to hold all the arguments
  v8::Local<v8::Object> all_args_object = v8::Object::New(isolate);
  all_args_object->Set(context, "allArgs", v8::Local<v8::Value>::New(isolate, args_object));
  all_args_object->Set(context, "receiver", v8::Local<v8::Value>::New(isolate, receiver_object));
  all_args_object->Set(context, "frameId", v8::Local<v8::Value>::New(isolate, frame_id_object));

  // Call the function
  v8::Local<v8::Value> result;
  if (!function->Call(context, v8::Undefined(isolate), 1, &all_args_object).ToLocal(&result)) {
    return false;
  }

  // Check if the result is a boolean
  if (!result->IsBoolean()) {
    return false;
  }

  // Return the result as a boolean
  return result->BooleanValue(isolate);
}

}  // namespace content
