struct dwc3_request {
    struct list_head node;
    struct usb_request *req;
    struct usb_gadget *gadget;
    struct dwc3 *dwc;
    int status;
};

static void dwc3_gadget_giveback(struct dwc3_request *req)
{
    struct dwc3 *dwc = req->dwc;
    struct usb_gadget *gadget = req->gadget;
    struct list_head *pos, *n;
    unsigned long flags;

    spin_lock_irqsave(&gadget->lock, flags);

    // Check if the request is still in the list
    list_for_each_safe(pos, n, &gadget->request_list) {
        struct dwc3_request *r = list_entry(pos, struct dwc3_request, node);
        if (r == req) {
            // Remove the request from the list
            list_del(pos);
            break;
        }
    }

    spin_unlock_irqrestore(&gadget->lock, flags);

    // Unmap the request before giving it back
    usb_gadget_unmap_request_by_dev(gadget, req->req, 0);

    // Complete the request
    usb_gadget_giveback_request(gadget, req->req);

    // Handle any necessary cleanup or logging
    if (req->status != 0) {
        dev_err(dwc->dev, "Request %p failed with status %d\n", req->req, req->status);
    }
}
