#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <sys/socket.h>
#include <sys/prctl.h>
#include <errno.h>

// Function to set the process as non-dumpable
int set_non_dumpable() {
    if (prctl(PR_SET_DUMPABLE, 0)) {
        perror("Failed to set process as non-dumpable");
        return -1;
    }
    return 0;
}

// Function to synchronize child processes
int synchronize_child_processes(int fd[2]) {
    if (write(fd[1], "sync", 4) < 0) {
        perror("Failed to synchronize child processes");
        return -1;
    }
    if (read(fd[0], NULL, 0) < 0) {
        perror("Failed to synchronize child processes");
        return -1;
    }
    return 0;
}

// Function to manage namespace operations
int nsexec(void (*child_func)(void *), void *child_arg) {
    int fd[2];
    if (socketpair(AF_UNIX, SOCK_STREAM, 0, fd) < 0) {
        perror("Failed to create socketpair");
        return -1;
    }

    pid_t pid = fork();
    if (pid < 0) {
        perror("Failed to fork");
        close(fd[0]);
        close(fd[1]);
        return -1;
    }

    if (pid == 0) {
        // Child process
        close(fd[0]);
        child_func(child_arg);
        close(fd[1]);
        _exit(0);
    } else {
        // Parent process
        close(fd[1]);
        if (set_non_dumpable() < 0) {
            close(fd[0]);
            return -1;
        }

        if (unshare(CLONE_NEWNS) < 0) {
            perror("Failed to unshare namespaces");
            close(fd[0]);
            return -1;
        }

        if (setns(fd[0], CLONE_NEWNS) < 0) {
            perror("Failed to set namespace");
            close(fd[0]);
            return -1;
        }

        if (synchronize_child_processes(fd) < 0) {
            close(fd[0]);
            return -1;
        }

        waitpid(pid, NULL, 0);
        close(fd[0]);
        return 0;
    }
}

int main() {
    void child_func(void *arg) {
        printf("Child process running\n");
    }

    if (nsexec(child_func, NULL) < 0) {
        perror("Failed to execute nsexec");
        return EXIT_FAILURE;
    }

    printf("Parent process exiting\n");
    return EXIT_SUCCESS;
}
