#include <arpa/inet.h>
#include <openssl/ssl.h>
#include <openssl/err.h>

#define MAX_REQUEST_SIZE 1024

int negotiate_handshake_newstyle_options(int sock, struct crypto_options *crypto_options) {
    struct nbd_request request;
    struct nbd_reply reply;
    int ret;

    // Initialize OpenSSL
    SSL_library_init();
    SSL_load_error_strings();
    OpenSSL_add_all_algorithms();

    // Create a new SSL context
    SSL_CTX *ctx = SSL_CTX_new(TLS_client_method());
    if (!ctx) {
        perror("SSL_CTX_new");
        return -1;
    }

    // Load the CA certificate
    if (SSL_CTX_load_verify_locations(ctx, "ca-cert.pem", NULL) != 1) {
        ERR_print_errors_fp(stderr);
        SSL_CTX_free(ctx);
        return -1;
    }

    // Create a new SSL connection
    SSL *ssl = SSL_new(ctx);
    if (!ssl) {
        ERR_print_errors_fp(stderr);
        SSL_CTX_free(ctx);
        return -1;
    }

    // Attach the SSL to the socket
    if (SSL_set_fd(ssl, sock) != 1) {
        ERR_print_errors_fp(stderr);
        SSL_free(ssl);
        SSL_CTX_free(ctx);
        return -1;
    }

    // Perform TLS handshake
    if (SSL_connect(ssl) != 1) {
        ERR_print_errors_fp(stderr);
        SSL_free(ssl);
        SSL_CTX_free(ctx);
        return -1;
    }

    // Read the NBD handshake request
    if (read(sock, &request, sizeof(request)) != sizeof(request)) {
        perror("read");
        SSL_free(ssl);
        SSL_CTX_free(ctx);
        return -1;
    }

    // Validate the request
    if (request.magic != NBD_MAGIC) {
        fprintf(stderr, "Invalid magic number\n");
        SSL_free(ssl);
        SSL_CTX_free(ctx);
        return -1;
    }

    if (request.size > MAX_REQUEST_SIZE) {
        fprintf(stderr, "Request size too large\n");
        SSL_free(ssl);
        SSL_CTX_free(ctx);
        return -1;
    }

    // Negotiate TLS options
    ret = crypto_negotiate_tls(crypto_options, ssl);
    if (ret != 0) {
        fprintf(stderr, "Failed to negotiate TLS options\n");
        SSL_free(ssl);
        SSL_CTX_free(ctx);
        return -1;
    }

    // Send the NBD handshake reply
    reply.magic = NBD_MAGIC;
    reply.size = crypto_options->block_size;
    reply.flags = NBD_FLAG_HAS_FLAGS;
    reply.export_name_len = strlen(crypto_options->export_name);
    reply.export_name = crypto_options->export_name;

    if (write(sock, &reply, sizeof(reply)) != sizeof(reply)) {
        perror("write");
        SSL_free(ssl);
        SSL_CTX_free(ctx);
        return -1;
    }

    // Clean up
    SSL_free(ssl);
    SSL_CTX_free(ctx);

    return 0;
}
