// Function to test Redis protocol parsing
int test_reply_reader() {
    redisReader *reader;
    redisReply *reply;
    char *data = "1\r\nHello\r\n";
    int len = strlen(data);

    // Initialize the redisReader
    reader = redisReaderCreate();
    if (reader == NULL) {
        fprintf(stderr, "Failed to create redisReader\n");
        return -1;
    }

    // Process the data
    if (redisReaderFeed(reader, data, len) == REDIS_ERR) {
        fprintf(stderr, "Failed to feed data to redisReader\n");
        redisReaderFree(reader);
        return -1;
    }

    // Get the reply
    reply = redisReaderGetReply(reader);
    if (reply == NULL) {
        fprintf(stderr, "Failed to get reply from redisReader\n");
        redisReaderFree(reader);
        return -1;
    }

    // Check the reply type and content
    if (reply->type != REDIS_REPLY_STRING || strcmp(reply->str, "Hello") != 0) {
        fprintf(stderr, "Invalid reply type or content\n");
        redisReaderFree(reader);
        return -1;
    }

    // Free the reply
    freeReplyObject(reply);

    // Free the redisReader
    redisReaderFree(reader);

    return 0;
}

