#include "regex.h"
#include "proftime.h"
#include "fast_breakcheck.h"
#include "debug.h"

int regmatch(const char *pattern, const char *string, int timeout) {
    regex_t regex;
    regmatch_t match;
    proftime_T start, end;
    int result;

    // Initialize the regex
    if (regcomp(&regex, pattern, REG_EXTENDED | REG_NEWLINE) != 0) {
        mch_errmsg("Failed to compile regex");
        return -1;
    }

    // Start timing
    proftime(&start);

    // Perform the regex match
    result = regexec(&regex, string, 1, &match, 0);

    // Stop timing
    proftime(&end);

    // Calculate the elapsed time
    double elapsed_time = proftime_diff(start, end);

    // Check for timeout
    if (elapsed_time > timeout) {
        mch_errmsg("Regex match timed out");
        result = -1;
    }

    // Clean up
    regfree(&regex);

    return result;
}
