// Function to get entry points from a NE binary object
SEXP r_bin_ne_get_entrypoints(SEXP obj) {
    // Check if the input object is of the correct type
    if (!IS_RTYPE(obj) || !Rf_isVector(obj) || Rf_length(obj) != 1) {
        Rf_error("Input object must be a single-element vector.");
    }

    // Check if the input object is a RList
    SEXP binlist = Rf_asRList(obj);
    if (binlist == R_NilValue) {
        Rf_error("Input object must be a valid RList.");
    }

    // Get the first element of the RList
    SEXP bin = binlist[0];
    if (!IS_RTYPE(bin) || !Rf_isVector(bin) || Rf_length(bin) != 1) {
        Rf_error("Each element of the RList must be a single-element vector.");
    }

    // Check if the first element is a RBinAddr
    SEXP addr = bin[0];
    if (!IS_RTYPE(addr) || !Rf_isVector(addr) || Rf_length(addr) != 1) {
        Rf_error("Each element of the RList must be a valid RBinAddr.");
    }

    // Extract the NE binary object from the RBinAddr
    NEBinary *ne_bin = r_bin_ne_from_addr(addr);
    if (!ne_bin) {
        Rf_error("Failed to extract NE binary object from RBinAddr.");
    }

    // Get the entry points from the NE binary object
    RList *entry_points = r_bin_ne_get_entry_points(ne_bin);
    if (!entry_points) {
        Rf_error("Failed to retrieve entry points from NE binary object.");
    }

    // Free the NE binary object
    r_bin_ne_free(ne_bin);

    // Return the entry points as an RList
    return Rf_duplicate(entry_points);
}
