    SC_HANDLE schSCManager = OpenSCManager(NULL, NULL, SC_MANAGER_CREATE_SERVICE);
    if (schSCManager == NULL)
    {
        std::cerr << "OpenSCManager failed with error: " << GetLastError() << std::endl;
        return false;
    }

    SC_HANDLE schService = CreateServiceW(
        schSCManager,
        displayName.c_str(),
